  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// 用户（通过手机号识别）\nmodel User {\n  id        String        @id @default(uuid())\n  phone     String        @unique\n  createdAt DateTime      @default(now())\n  updatedAt DateTime      @updatedAt\n  sessions  ChatSession[]\n}\n\n// 店铺/商户\nmodel Store {\n  id              String        @id @default(uuid())\n  name            String\n  storeType       StoreType\n  difyDatasetId   String? // Dify 知识库 ID\n  fileStoragePath String? // 本地文件存储目录\n  createdAt       DateTime      @default(now())\n  updatedAt       DateTime      @updatedAt\n  sessions        ChatSession[]\n  trainingJobs    TrainingJob[]\n}\n\nenum StoreType {\n  SELF // 自营\n  MERCHANT // 第三方店铺\n}\n\n// 聊天会话\nmodel ChatSession {\n  id                 String        @id @default(uuid())\n  userId             String\n  user               User          @relation(fields: [userId], references: [id])\n  storeId            String\n  store              Store         @relation(fields: [storeId], references: [id])\n  storeType          StoreType\n  channel            String // 小程序/H5/App\n  difyConversationId String? // Dify 会话ID\n  status             SessionStatus @default(OPEN)\n  lastActiveAt       DateTime      @default(now())\n  createdAt          DateTime      @default(now())\n  updatedAt          DateTime      @updatedAt\n\n  messages       ChatMessage[]\n  handoffTickets HandoffTicket[]\n}\n\nenum SessionStatus {\n  OPEN // AI 对话中\n  HANDOFF // 已转人工\n  CLOSED // 会话已关闭\n}\n\n// 聊天消息\nmodel ChatMessage {\n  id          String      @id @default(uuid())\n  sessionId   String\n  session     ChatSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  senderType  SenderType\n  content     String\n  messageType MessageType @default(TEXT)\n  rawPayload  Json? // Dify 原始响应\n  createdAt   DateTime    @default(now())\n}\n\nenum SenderType {\n  USER // 用户\n  AI // AI\n  HUMAN // 人工客服\n  SYSTEM // 系统消息\n}\n\nenum MessageType {\n  TEXT // 文本\n  EVENT // 事件（如转人工）\n  CARD // 卡片（如订单卡片）\n}\n\n// 转人工工单\nmodel HandoffTicket {\n  id              String        @id @default(uuid())\n  sessionId       String\n  session         ChatSession   @relation(fields: [sessionId], references: [id])\n  status          HandoffStatus @default(PENDING)\n  queueNo         Int // 排队号\n  assignedAgentId String? // 分配的客服ID\n  createdAt       DateTime      @default(now())\n  updatedAt       DateTime      @updatedAt\n}\n\nenum HandoffStatus {\n  PENDING // 待接单\n  ANSWERED // 已接单\n  CLOSED // 已关闭\n}\n\n// 订单\nmodel Order {\n  id              String      @id @default(uuid())\n  orderNo         String      @unique // DD开头的订单号\n  status          OrderStatus @default(PENDING)\n  payStatus       PayStatus   @default(UNPAID)\n  amount          Float       @default(0) // 订单金额\n  discountAmount  Float       @default(0) // 优惠金额\n  actualAmount    Float       @default(0) // 实付金额\n  quantity        Int         @default(1) // 商品数量\n  productName     String // 商品名称\n  productPrice    Float       @default(0) // 商品单价\n  shippingAddress String? // 收货地址\n  receiverName    String? // 收货人\n  receiverPhone   String? // 联系电话\n  createdAt       DateTime    @default(now())\n  paidAt          DateTime? // 支付时间\n  shippedAt       DateTime? // 发货时间\n  deliveredAt     DateTime? // 送达时间\n  updatedAt       DateTime    @updatedAt\n\n  // 物流信息\n  logistics Logistics?\n}\n\nenum OrderStatus {\n  PENDING // 待支付\n  PAID // 已支付\n  TO_BE_SHIPPED // 待发货\n  SHIPPED // 已发货\n  DELIVERED // 已送达\n  CANCELLED // 已取消\n  REFUNDED // 已退款\n}\n\nenum PayStatus {\n  UNPAID // 未支付\n  PAID // 已支付\n  REFUNDED // 已退款\n}\n\n// 物流信息\nmodel Logistics {\n  id                String          @id @default(uuid())\n  orderId           String          @unique\n  order             Order           @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  carrier           String // 快递公司\n  trackingNo        String // 运单号\n  status            LogisticsStatus @default(PENDING)\n  currentLocation   String? // 当前所在地\n  estimatedDelivery DateTime? // 预计送达时间\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n\n  // 物流轨迹\n  events LogisticsEvent[]\n}\n\nenum LogisticsStatus {\n  PENDING // 待发货\n  IN_TRANSIT // 运输中\n  DELIVERED // 已送达\n}\n\n// 物流轨迹节点\nmodel LogisticsEvent {\n  id          String    @id @default(uuid())\n  logisticsId String\n  logistics   Logistics @relation(fields: [logisticsId], references: [id], onDelete: Cascade)\n  time        DateTime  @default(now())\n  location    String\n  description String\n}\n\n// 训练任务状态\nenum TrainingStatus {\n  PENDING // 待处理\n  PROCESSING // 处理中\n  COMPLETED // 已完成\n  FAILED // 失败\n}\n\n// 训练任务\nmodel TrainingJob {\n  id           String         @id @default(uuid())\n  storeId      String\n  store        Store          @relation(fields: [storeId], references: [id])\n  fileName     String\n  filePath     String // 本地文件路径\n  status       TrainingStatus @default(PENDING)\n  errorMessage String?\n  createdAt    DateTime       @default(now())\n  completedAt  DateTime?\n}\n",
